1	package routehealth
2	
3	import (
4		"fmt"
5		"strings"
6		"sync"
7		"time"
8	
9		"github.com/easel/fizeau/internal/routing"
10	)
11	
12	// DefaultCooldown is the process-local route-attempt TTL used when service
13	// configuration does not provide a health cooldown.
14	const DefaultCooldown = 30 * time.Second
15	
16	// Attempt records availability feedback for one routed attempt.
17	type Attempt struct {
18		Harness   string
19		Provider  string
20		Model     string
21		Endpoint  string
22		Status    string
23		Reason    string
24		Error     string
25		Duration  time.Duration
26		Timestamp time.Time
27	}
28	
29	// Key is the normalized route-attempt identity.
30	type Key struct {
31		Harness  string
32		Provider string
33		Model    string
34		Endpoint string
35	}
36	
37	// Record is an active route-attempt failure.
38	type Record struct {
39		Key        Key
40		Status     string
41		Reason     string
42		Error      string
43		Duration   time.Duration
44		RecordedAt time.Time
45	}
46	
47	type metricRecord struct {
48		attempts      int
49		successes     int
50		totalDuration time.Duration
51		recordedAt    time.Time
52	}
53	
54	// Store owns process-local route-attempt failure feedback and reliability
55	// metrics. It is safe for concurrent use.
56	type Store struct {
57		mu       sync.RWMutex
58		failures map[Key]Record
59		metrics  map[Key]metricRecord
60	}
61	
62	// NewStore returns an empty route-health store.
63	func NewStore() *Store {
64		return &Store{
65			failures: make(map[Key]Record),
66			metrics:  make(map[Key]metricRecord),
67		}
68	}
69	
70	// RecordAttempt records availability feedback. Success clears matching active
71	// failures; non-success records an active failure and updates metrics.
72	func (s *Store) RecordAttempt(attempt Attempt) error {
73		key := NormalizeKey(attempt)
74		if key.Harness == "" && key.Provider == "" {
75			return fmt.Errorf("route attempt requires harness or provider")
76		}
77		status := strings.ToLower(strings.TrimSpace(attempt.Status))
78		if status == "" {
79			return fmt.Errorf("route attempt status is required")
80		}
81		recordedAt := attempt.Timestamp
82		if recordedAt.IsZero() {
83			recordedAt = time.Now()
84		}
85		recordedAt = recordedAt.UTC()
86	
87		s.mu.Lock()
88		defer s.mu.Unlock()
89		if s.failures == nil {
90			s.failures = make(map[Key]Record)
91		}
92		if s.metrics == nil {
93			s.metrics = make(map[Key]metricRecord)
94		}
95		s.recordMetricLocked(key, Succeeded(status), attempt.Duration, recordedAt)
96	
97		if Succeeded(status) {
98			s.clearFailuresLocked(key)
99			return nil
100		}
101	
102		s.failures[key] = Record{
103			Key:        key,
104			Status:     status,
105			Reason:     strings.TrimSpace(attempt.Reason),
106			Error:      strings.TrimSpace(attempt.Error),
107			Duration:   attempt.Duration,
108			RecordedAt: recordedAt,
109		}
110		return nil
111	}
112	
113	func (s *Store) recordMetricLocked(key Key, success bool, duration time.Duration, recordedAt time.Time) {
114		record := s.metrics[key]
115		record.attempts++
116		if success {
117			record.successes++
118		}
119		if duration > 0 {
120			record.totalDuration += duration
121		}
122		record.recordedAt = recordedAt
123		s.metrics[key] = record
124	}
125	
126	// NormalizeKey returns the normalized route-attempt key for attempt.
127	func NormalizeKey(attempt Attempt) Key {
128		return Key{
129			Harness:  strings.TrimSpace(attempt.Harness),
130			Provider: strings.TrimSpace(attempt.Provider),
131			Model:    strings.TrimSpace(attempt.Model),
132			Endpoint: strings.TrimSpace(attempt.Endpoint),
133		}
134	}
135	
136	// Succeeded reports whether status is a success spelling.
137	func Succeeded(status string) bool {
138		switch status {
139		case "success", "ok", "succeeded":
140			return true
141		default:
142			return false
143		}
144	}
145	
146	func (s *Store) clearFailuresLocked(key Key) {
147		for existing := range s.failures {
148			if KeysMatch(existing, key) {
149				delete(s.failures, existing)
150			}
151		}
152	}
153	
154	// KeysMatch reports whether existing satisfies every non-empty query field.
155	func KeysMatch(existing, query Key) bool {
156		if query.Harness != "" && existing.Harness != query.Harness {
157			return false
158		}
159		if query.Provider != "" && existing.Provider != query.Provider {
160			return false
161		}
162		if query.Model != "" && existing.Model != query.Model {
163			return false
164		}
165		if query.Endpoint != "" && existing.Endpoint != query.Endpoint {
166			return false
167		}
168		return true
169	}
170	
171	// ActiveAttempts returns active failure records and removes expired records
172	// from the store.
173	func (s *Store) ActiveAttempts(now time.Time, ttl time.Duration) []Record {
174		if s == nil {
175			return nil
176		}
177		if ttl <= 0 {
178			ttl = DefaultCooldown
179		}
180		if now.IsZero() {
181			now = time.Now()
182		}
183		now = now.UTC()
184	
185		s.mu.Lock()
186		defer s.mu.Unlock()
187		if len(s.failures) == 0 {
188			return nil
189		}
190		out := make([]Record, 0, len(s.failures))
191		for key, record := range s.failures {
192			if !record.RecordedAt.Add(ttl).After(now) {
193				delete(s.failures, key)
194				continue
195			}
196			out = append(out, record)
197		}
198		return out
199	}
200	
201	// MetricSignals returns provider/model success-rate and latency maps suitable
202	// for routing inputs.
203	func (s *Store) MetricSignals(now time.Time, ttl time.Duration) (map[string]float64, map[string]float64) {
204		if s == nil {
205			return nil, nil
206		}
207		if ttl <= 0 {
208			ttl = DefaultCooldown
209		}
210		if now.IsZero() {
211			now = time.Now()
212		}
213		now = now.UTC()
214	
215		s.mu.RLock()
216		defer s.mu.RUnlock()
217		if len(s.metrics) == 0 {
218			return nil, nil
219		}
220		successRate := make(map[string]float64, len(s.metrics))
221		latencyMS := make(map[string]float64, len(s.metrics))
222		for key, record := range s.metrics {
223			if record.attempts <= 0 {
224				continue
225			}
226			if !record.recordedAt.IsZero() && !record.recordedAt.Add(ttl).After(now) {
227				continue
228			}
229			metricKey := ProviderModelKey(key)
230			successRate[metricKey] = float64(record.successes) / float64(record.attempts)
231			if record.totalDuration > 0 {
232				latencyMS[metricKey] = float64(record.totalDuration.Milliseconds()) / float64(record.attempts)
233			}
234		}
235		return successRate, latencyMS
236	}
237	
238	// ProviderModelKey returns the routing provider/model metric key for key.
239	func ProviderModelKey(key Key) string {
240		return routing.ProviderModelKey(key.Provider, key.Endpoint, key.Model)
241	}
