1	package routehealth
2	
3	import (
4		"sort"
5		"strings"
6		"sync"
7		"time"
8	)
9	
10	// DefaultLeaseTTL bounds how long an in-process sticky route lease may live
11	// without being refreshed.
12	const DefaultLeaseTTL = 5 * time.Minute
13	
14	// LeaseKey identifies one sticky lease scope.
15	type LeaseKey struct {
16		StickyKey string
17	}
18	
19	// Lease describes one sticky endpoint assignment.
20	type Lease struct {
21		Key         LeaseKey
22		Provider    string
23		Endpoint    string
24		Model       string
25		AcquiredAt  time.Time
26		RefreshedAt time.Time
27		ExpiresAt   time.Time
28	}
29	
30	// LeaseInvalidation records why a lease was removed.
31	type LeaseInvalidation struct {
32		Key        LeaseKey
33		Provider   string
34		Endpoint   string
35		Model      string
36		Reason     string
37		RecordedAt time.Time
38	}
39	
40	// LeaseStore owns in-process sticky route assignments. It is safe for
41	// concurrent use.
42	type LeaseStore struct {
43		mu            sync.Mutex
44		leases        map[LeaseKey]Lease
45		invalidations map[LeaseKey]LeaseInvalidation
46	}
47	
48	// NewLeaseStore returns an empty lease store.
49	func NewLeaseStore() *LeaseStore {
50		return &LeaseStore{
51			leases:        make(map[LeaseKey]Lease),
52			invalidations: make(map[LeaseKey]LeaseInvalidation),
53		}
54	}
55	
56	// NormalizeLeaseKey trims whitespace from the sticky key.
57	func NormalizeLeaseKey(stickyKey string) LeaseKey {
58		return LeaseKey{StickyKey: strings.TrimSpace(stickyKey)}
59	}
60	
61	// Live returns the current lease for key when it has not expired.
62	func (s *LeaseStore) Live(now time.Time, key LeaseKey) (Lease, bool) {
63		if s == nil {
64			return Lease{}, false
65		}
66		now = normalizeLeaseNow(now)
67	
68		s.mu.Lock()
69		defer s.mu.Unlock()
70		s.expireLocked(now)
71		lease, ok := s.leases[key]
72		if !ok {
73			return Lease{}, false
74		}
75		return lease, true
76	}
77	
78	// Acquire stores or refreshes a lease for key.
79	func (s *LeaseStore) Acquire(now time.Time, ttl time.Duration, key LeaseKey, provider, endpoint, model string) Lease {
80		if s == nil {
81			return Lease{}
82		}
83		now = normalizeLeaseNow(now)
84		if ttl <= 0 {
85			ttl = DefaultLeaseTTL
86		}
87		key = NormalizeLeaseKey(key.StickyKey)
88		provider = strings.TrimSpace(provider)
89		endpoint = strings.TrimSpace(endpoint)
90		model = strings.TrimSpace(model)
91	
92		s.mu.Lock()
93		defer s.mu.Unlock()
94		s.expireLocked(now)
95	
96		lease := Lease{
97			Key:         key,
98			Provider:    provider,
99			Endpoint:    endpoint,
100			Model:       model,
101			AcquiredAt:  now,
102			RefreshedAt: now,
103			ExpiresAt:   now.Add(ttl),
104		}
105		if existing, ok := s.leases[key]; ok {
106			if existing.Provider == provider && existing.Endpoint == endpoint && existing.Model == model {
107				lease.AcquiredAt = existing.AcquiredAt
108			}
109		}
110		s.leases[key] = lease
111		delete(s.invalidations, key)
112		return lease
113	}
114	
115	// Invalidate removes the lease for key and records the reason.
116	func (s *LeaseStore) Invalidate(now time.Time, key LeaseKey, reason string) (LeaseInvalidation, bool) {
117		if s == nil {
118			return LeaseInvalidation{}, false
119		}
120		now = normalizeLeaseNow(now)
121		key = NormalizeLeaseKey(key.StickyKey)
122	
123		s.mu.Lock()
124		defer s.mu.Unlock()
125		s.expireLocked(now)
126		lease, ok := s.leases[key]
127		if !ok {
128			return LeaseInvalidation{}, false
129		}
130		delete(s.leases, key)
131		invalidation := LeaseInvalidation{
132			Key:        key,
133			Provider:   lease.Provider,
134			Endpoint:   lease.Endpoint,
135			Model:      lease.Model,
136			Reason:     strings.TrimSpace(reason),
137			RecordedAt: now,
138		}
139		s.invalidations[key] = invalidation
140		return invalidation, true
141	}
142	
143	// InvalidateEndpoint removes every lease for the provider/model scope that
144	// points at the named endpoint and records the supplied reason.
145	func (s *LeaseStore) InvalidateEndpoint(now time.Time, provider, endpoint, model, reason string) []LeaseInvalidation {
146		if s == nil {
147			return nil
148		}
149		now = normalizeLeaseNow(now)
150		provider = strings.TrimSpace(provider)
151		endpoint = strings.TrimSpace(endpoint)
152		model = strings.TrimSpace(model)
153	
154		s.mu.Lock()
155		defer s.mu.Unlock()
156		s.expireLocked(now)
157		if len(s.leases) == 0 {
158			return nil
159		}
160		var out []LeaseInvalidation
161		for key, lease := range s.leases {
162			if provider != "" && lease.Provider != provider {
163				continue
164			}
165			if endpoint != "" && lease.Endpoint != endpoint {
166				continue
167			}
168			if model != "" && lease.Model != model {
169				continue
170			}
171			delete(s.leases, key)
172			invalidation := LeaseInvalidation{
173				Key:        key,
174				Provider:   lease.Provider,
175				Endpoint:   lease.Endpoint,
176				Model:      lease.Model,
177				Reason:     strings.TrimSpace(reason),
178				RecordedAt: now,
179			}
180			s.invalidations[key] = invalidation
181			out = append(out, invalidation)
182		}
183		return out
184	}
185	
186	// LiveByScope returns the live leases for provider/model, ordered by sticky
187	// key for deterministic tests.
188	func (s *LeaseStore) LiveByScope(now time.Time, provider, model string) []Lease {
189		if s == nil {
190			return nil
191		}
192		now = normalizeLeaseNow(now)
193		provider = strings.TrimSpace(provider)
194		model = strings.TrimSpace(model)
195	
196		s.mu.Lock()
197		defer s.mu.Unlock()
198		s.expireLocked(now)
199		if len(s.leases) == 0 {
200			return nil
201		}
202		out := make([]Lease, 0, len(s.leases))
203		for _, lease := range s.leases {
204			if provider != "" && lease.Provider != provider {
205				continue
206			}
207			if model != "" && lease.Model != model {
208				continue
209			}
210			out = append(out, lease)
211		}
212		sort.Slice(out, func(i, j int) bool {
213			if out[i].Endpoint != out[j].Endpoint {
214				return out[i].Endpoint < out[j].Endpoint
215			}
216			return out[i].Key.StickyKey < out[j].Key.StickyKey
217		})
218		return out
219	}
220	
221	// LeaseCounts returns the live lease count per endpoint for provider/model.
222	func (s *LeaseStore) LeaseCounts(now time.Time, provider, model string) map[string]int {
223		leases := s.LiveByScope(now, provider, model)
224		if len(leases) == 0 {
225			return nil
226		}
227		counts := make(map[string]int, len(leases))
228		for _, lease := range leases {
229			counts[lease.Endpoint]++
230		}
231		return counts
232	}
233	
234	// LastInvalidation returns the most recent invalidation recorded for key.
235	func (s *LeaseStore) LastInvalidation(key LeaseKey) (LeaseInvalidation, bool) {
236		if s == nil {
237			return LeaseInvalidation{}, false
238		}
239		key = NormalizeLeaseKey(key.StickyKey)
240	
241		s.mu.Lock()
242		defer s.mu.Unlock()
243		invalidation, ok := s.invalidations[key]
244		return invalidation, ok
245	}
246	
247	func (s *LeaseStore) expireLocked(now time.Time) {
248		for key, lease := range s.leases {
249			if lease.ExpiresAt.IsZero() || lease.ExpiresAt.After(now) {
250				continue
251			}
252			delete(s.leases, key)
253			s.invalidations[key] = LeaseInvalidation{
254				Key:        key,
255				Provider:   lease.Provider,
256				Endpoint:   lease.Endpoint,
257				Model:      lease.Model,
258				Reason:     "expired",
259				RecordedAt: now,
260			}
261		}
262	}
263	
264	func normalizeLeaseNow(now time.Time) time.Time {
265		if now.IsZero() {
266			return time.Now().UTC()
267		}
268		return now.UTC()
269	}
