246	func routeSnapshotCandidateIndex(snapshot modelsnapshot.ModelSnapshot) map[routeSnapshotCandidateKey]modelsnapshot.KnownModel {
247		if len(snapshot.Models) == 0 {
248			return nil
249		}
250		out := make(map[routeSnapshotCandidateKey]modelsnapshot.KnownModel, len(snapshot.Models))
251		for _, row := range snapshot.Models {
252			key := routeSnapshotCandidateKey{
253				Provider:       strings.TrimSpace(row.Provider),
254				Endpoint:       strings.TrimSpace(row.EndpointName),
255				ServerInstance: strings.TrimSpace(serverinstance.Normalize(row.EndpointBaseURL, row.ServerInstance)),
256				Model:          strings.TrimSpace(row.ID),
257			}
258			if key.Provider == "" || key.Model == "" {
259				continue
260			}
261			if _, exists := out[key]; exists {
262				continue
263			}
264			out[key] = row
265		}
266		return out
267	}
