269	func routeSnapshotEvidenceForCandidate(candidate RouteCandidate, snapshot modelsnapshot.ModelSnapshot) (modelsnapshot.KnownModel, bool) {
270		index := routeSnapshotCandidateIndex(snapshot)
271		if len(index) == 0 {
272			return modelsnapshot.KnownModel{}, false
273		}
274		provider := strings.TrimSpace(candidate.Provider)
275		endpoint := strings.TrimSpace(candidate.Endpoint)
276		serverInstance := strings.TrimSpace(candidate.ServerInstance)
277		model := strings.TrimSpace(candidate.Model)
278		if base, ep, ok := splitEndpointProviderRef(provider); ok {
279			provider = base
280			if endpoint == "" {
281				endpoint = ep
282			}
283		}
284		keys := []routeSnapshotCandidateKey{{
285			Provider:       provider,
286			Endpoint:       endpoint,
287			ServerInstance: serverInstance,
288			Model:          model,
289		}}
290		if endpoint == "" {
291			keys = append(keys, routeSnapshotCandidateKey{
292				Provider:       provider,
293				ServerInstance: serverInstance,
294				Model:          model,
295			})
296		}
297		if serverInstance == "" {
298			keys = append(keys, routeSnapshotCandidateKey{
299				Provider: provider,
300				Endpoint: endpoint,
301				Model:    model,
302			})
303			if endpoint == "" {
304				keys = append(keys, routeSnapshotCandidateKey{
305					Provider: provider,
306					Model:    model,
307				})
308			}
309		}
310		for _, key := range keys {
311			if row, ok := index[key]; ok {
312				return row, true
313			}
314		}
315		for _, row := range snapshot.Models {
316			rowProvider := strings.TrimSpace(row.Provider)
317			rowEndpoint := strings.TrimSpace(row.EndpointName)
318			rowServerInstance := strings.TrimSpace(serverinstance.Normalize(row.EndpointBaseURL, row.ServerInstance))
319			if rowProvider != provider || strings.TrimSpace(row.ID) != model {
320				continue
321			}
322			if endpoint != "" && rowEndpoint != endpoint {
323				continue
324			}
325			if serverInstance != "" && rowServerInstance != serverInstance {
326				continue
327			}
328			return row, true
329		}
330		return modelsnapshot.KnownModel{}, false
331	}
