434	func routeUtilizationStateFromSample(sample utilization.EndpointUtilization) RouteUtilizationState {
435		out := RouteUtilizationState{
436			Source:     string(sample.Source),
437			Freshness:  string(sample.Freshness),
438			ObservedAt: sample.ObservedAt,
439		}
440		if sample.ActiveRequests != nil {
441			out.ActiveRequests = utilization.Int(*sample.ActiveRequests)
442		}
443		if sample.QueuedRequests != nil {
444			out.QueuedRequests = utilization.Int(*sample.QueuedRequests)
445		}
446		if sample.MaxConcurrency != nil {
447			out.MaxConcurrency = utilization.Int(*sample.MaxConcurrency)
448		}
449		if sample.CacheUsage != nil {
450			v := *sample.CacheUsage
451			out.CachePressure = &v
452		}
453		if out.CachePressure == nil && sample.MaxConcurrency != nil && *sample.MaxConcurrency > 0 {
454			total := 0
455			if sample.ActiveRequests != nil {
456				total += *sample.ActiveRequests
457			}
458			if sample.QueuedRequests != nil {
459				total += *sample.QueuedRequests
460			}
461			pressure := float64(total) / float64(*sample.MaxConcurrency)
462			out.CachePressure = &pressure
463		}
464		return out
465	}
