498	// escalatePolicyLadder walks routing.PolicyEscalationLadder when Resolve
499	// returns a "no eligible candidate" error and the request's policy is in
500	// the ladder. Returns (true, decision, nil) when a higher tier resolves to
501	// an eligible candidate, or (true, nil, *routing.ErrNoLiveProvider) when
502	// the entire remaining ladder is also empty. Returns (false, _, _) when
503	// escalation does not apply (hard pin error, policy not in ladder, etc.).
504	func escalatePolicyLadder(req routing.Request, in routing.Inputs, origErr error, displayPolicy string) (bool, *routing.Decision, error) {
505		if origErr == nil || req.Policy == "" {
506			return false, nil, nil
507		}
508		if !shouldEscalateOnError(origErr) {
509			return false, nil, nil
510		}
511		startIdx := -1
512		for i, p := range routing.PolicyEscalationLadder {
513			if p == req.Policy {
514				startIdx = i
515				break
516			}
517		}
518		if startIdx < 0 {
519			return false, nil, nil
520		}
521		for i := startIdx + 1; i < len(routing.PolicyEscalationLadder); i++ {
522			probe := req
523			probe.Policy = routing.PolicyEscalationLadder[i]
524			dec, err := routing.Resolve(probe, in)
525			if err == nil && dec != nil && dec.Harness != "" {
526				return true, dec, nil
527			}
528		}
529		starting := displayPolicy
530		if starting == "" {
531			starting = req.Policy
532		}
533		return true, nil, &routing.ErrNoLiveProvider{
534			PromptTokens:   req.EstimatedPromptTokens,
535			RequiresTools:  req.RequiresTools,
536			StartingPolicy: starting,
537			MinPower:       req.MinPower,
538			MaxPower:       req.MaxPower,
539			AllowLocal:     req.AllowLocal,
540		}
541	}
542	
543	// shouldEscalateOnError gates ladder escalation to "no eligible candidate"
544	// errors. Hard caller-pin conflicts (ErrHarnessModelIncompatible,
545	// ErrPolicyRequirementUnsatisfied) are surfaced as-is — escalating past an explicit
546	// pin would silently change the caller's intent.
547	func shouldEscalateOnError(err error) bool {
548		var modelConstraintAmbiguous *ErrModelConstraintAmbiguous
549		if errors.As(err, &modelConstraintAmbiguous) {
550			return false
551		}
552		var modelConstraintNoMatch *ErrModelConstraintNoMatch
553		if errors.As(err, &modelConstraintNoMatch) {
554			return false
555		}
556		var modelErr *routing.ErrHarnessModelIncompatible
557		if errors.As(err, &modelErr) {
558			return false
559		}
560		var pinErr *routing.ErrUnsatisfiablePin
561		if errors.As(err, &pinErr) {
562			return false
563		}
564		var policyErr *routing.ErrPolicyRequirementUnsatisfied
565		if errors.As(err, &policyErr) {
566			return false
567		}
568		return true
569	}
570	
571	func publicRoutingError(err error, candidates []RouteCandidate, requestedPolicy ...string) error {
572		displayPolicy := func(policy string) string {
573			if len(requestedPolicy) > 0 && requestedPolicy[0] != "" {
574				return requestedPolicy[0]
575			}
576			return policy
577		}
578		var modelErr *routing.ErrHarnessModelIncompatible
579		if errors.As(err, &modelErr) {
580			return withRouteCandidates(&ErrHarnessModelIncompatible{
581				Harness:         modelErr.Harness,
582				Model:           modelErr.Model,
583				SupportedModels: append([]string(nil), modelErr.SupportedModels...),
584			}, candidates)
585		}
586		var policyErr *routing.ErrPolicyRequirementUnsatisfied
587		if errors.As(err, &policyErr) {
588			return withRouteCandidates(&ErrPolicyRequirementUnsatisfied{
589				Policy:       displayPolicy(policyErr.Policy),
590				Requirement:  policyErr.Requirement,
591				AttemptedPin: policyErr.AttemptedPin,
592				Rejected:     policyErr.Rejected,
593			}, candidates)
594		}
595		var unknownPolicyErr *routing.ErrUnknownPolicy
596		if errors.As(err, &unknownPolicyErr) {
597			return withRouteCandidates(&ErrUnknownPolicy{
598				Policy: displayPolicy(unknownPolicyErr.Policy),
599			}, candidates)
600		}
601		var pinErr *routing.ErrUnsatisfiablePin
602		if errors.As(err, &pinErr) {
603			return withRouteCandidates(&ErrUnsatisfiablePin{
604				Pin:    pinErr.Pin,
605				Reason: pinErr.Reason,
606			}, candidates)
607		}
608		var noLiveErr *routing.ErrNoLiveProvider
609		if errors.As(err, &noLiveErr) {
610			return withRouteCandidates(&ErrNoLiveProvider{
611				PromptTokens:   noLiveErr.PromptTokens,
612				RequiresTools:  noLiveErr.RequiresTools,
613				StartingPolicy: displayPolicy(noLiveErr.StartingPolicy),
614			}, candidates)
615		}
616		var quotaErr *routing.ErrAllProvidersQuotaExhausted
617		if errors.As(err, &quotaErr) {
618			return withRouteCandidates(&NoViableProviderForNow{
619				RetryAfter:         quotaErr.RetryAfter,
620				ExhaustedProviders: append([]string(nil), quotaErr.ExhaustedProviders...),
621			}, candidates)
622		}
623		return withRouteCandidates(err, candidates)
624	}
