626	func withRouteCandidates(err error, candidates []RouteCandidate) error {
627		if err == nil || len(candidates) == 0 {
628			return err
629		}
630		return &routeDecisionError{
631			err:        err,
632			candidates: append([]RouteCandidate(nil), candidates...),
633		}
634	}
