636	func (s *service) applyRouteAttemptCooldowns(in *routing.Inputs) {
637		if in == nil {
638			return
639		}
640		ttl := s.routeAttemptTTL()
641		records := s.activeRouteAttempts(time.Now(), ttl)
642		if len(records) == 0 {
643			return
644		}
645		if in.ProviderCooldowns == nil {
646			in.ProviderCooldowns = make(map[string]time.Time)
647		}
648		if in.CooldownDuration <= 0 {
649			in.CooldownDuration = ttl
650		}
651		for _, record := range records {
652			if record.Key.Provider != "" {
653				existing, ok := in.ProviderCooldowns[record.Key.Provider]
654				if !ok || record.RecordedAt.After(existing) {
655					in.ProviderCooldowns[record.Key.Provider] = record.RecordedAt
656				}
657				// FEAT-004 AC-28: route-attempt failures with dial-class errors
658				// (host unreachable, not a stream-level glitch) are dispatchability
659				// failures, not just non-fatal health risk. Promote them to
660				// ProviderUnreachable so the engine hard-gates on the next call
661				// without waiting for the snapshot's background refresh to catch
662				// up. Non-dial failures (5xx mid-stream, 4xx, context canceled)
663				// stay as soft demotion to preserve sticky-lease across single
664				// transient hiccups.
665				if isDispatchabilityFailure(record.Error) {
666					if in.ProviderUnreachable == nil {
667						in.ProviderUnreachable = make(map[string]time.Time)
668					}
669					existing, ok := in.ProviderUnreachable[record.Key.Provider]
670					if !ok || record.RecordedAt.After(existing) {
671						in.ProviderUnreachable[record.Key.Provider] = record.RecordedAt
672					}
673				}
674			}
675			if record.Key.Provider == "" && record.Key.Harness != "" {
676				for i := range in.Harnesses {
677					if in.Harnesses[i].Name == record.Key.Harness {
678						in.Harnesses[i].InCooldown = true
679					}
680				}
681			}
682		}
683	}
