685	func (s *service) routeAttemptTTL() time.Duration {
686		if s.opts.ServiceConfig == nil {
687			return defaultRouteAttemptCooldown
688		}
689		ttl := s.opts.ServiceConfig.HealthCooldown()
690		if ttl <= 0 {
691			return defaultRouteAttemptCooldown
692		}
693		return ttl
694	}
