696	// buildRoutingInputs assembles routing.Inputs from the service's registry
697	// and snapshot-derived provider inventory. The public routing engine stays
698	// unchanged; only the source of provider/model candidates changes.
699	func (s *service) buildRoutingInputs(ctx context.Context) routing.Inputs {
700		// FEAT-004 §Snapshot Freshness — synchronous-freshness contract: at route
701		// decision time, refresh stale providers in-line so the engine sees
702		// current reachability. Fresh providers short-circuit on cache. Caps the
703		// per-route cost at ~5s × stale-provider-count (5s = discoveryRefresh
704		// deadline per source) instead of forcing every source to re-probe.
705		inputs, _ := s.buildRoutingInputsWithCatalog(ctx, serviceRoutingCatalog(), modelsnapshot.RefreshIfStale)
706		return inputs
707	}
708	
709	func (s *service) buildRoutingInputsWithCatalog(ctx context.Context, cat *modelcatalog.Catalog, refresh modelsnapshot.RefreshMode) (routing.Inputs, modelsnapshot.ModelSnapshot) {
710		statuses := s.registry.Discover()
711		statusByName := make(map[string]harnesses.HarnessStatus, len(statuses))
712		for _, st := range statuses {
713			statusByName[st.Name] = st
714		}
715		now := time.Now().UTC()
716		var snapshot modelsnapshot.ModelSnapshot
717		if s.opts.ServiceConfig != nil {
718			if cacheRoot, err := serviceSnapshotCacheRoot(); err == nil {
719				snapshot, _ = assembleModelSnapshotFromServiceConfigWithOptions(
720					ctx,
721					s.opts.ServiceConfig,
722					cat,
723					cacheRoot,
724					modelsnapshot.AssembleOptions{Refresh: refresh},
725				)
726			}
727		}
728	
729		var entries []routing.HarnessEntry
730		for _, name := range s.registry.Names() {
731			cfg, ok := s.registry.Get(name)
732			if !ok {
733				continue
734			}
735			st := statusByName[name]
736			entry := routingHarnessEntryFromMetadata(name, cfg, st)
737			if name == "fiz" && s.opts.ServiceConfig == nil {
738				entry.AutoRoutingEligible = false
739			}
740	
741			if qs, ok := subscriptionQuotaForHarness(name, time.Now()); ok {
742				entry.QuotaOK = qs.OK
743				entry.QuotaStale = qs.Present && !qs.Fresh
744				entry.SubscriptionOK = qs.OK
745				entry.QuotaPercentUsed = qs.PercentUsed
746				entry.QuotaTrend = qs.Trend
747				entry.QuotaReason = qs.Reason
748			}
749	
750			// Native "fiz" harness: enumerate snapshot-derived provider rows.
751			if name == "fiz" && s.opts.ServiceConfig != nil {
752				entry.Providers = s.snapshotProviderEntries(ctx, cat, snapshot)
753				// Tool support for the agent harness is per-(provider, model);
754				// the harness-level baseline is whether ANY provider supports
755				// tools. Engine OR-combines harness and provider SupportsTools
756				// so this lets a per-model no_tools catalog flag actually fire
757				// the RequiresTools gate when every provider's resolved model
758				// is no-tools.
759				if len(entry.Providers) > 0 {
760					entry.SupportsTools = anyProviderSupportsTools(entry.Providers)
761				} else {
762					entry.Available = false
763				}
764			}
765			s.applySubscriptionRoutingCost(&entry, cat)
766			entries = append(entries, entry)
767		}
768		successRate, latencyMS := s.routeMetricSignals(now, s.routeAttemptTTL())
769	
770		// FEAT-004 AC-28: known-down endpoints are dispatchability failures.
771		// Surface provider-level dial failures from the snapshot's discovery
772		// sources via ProviderUnreachable so the routing engine hard-gates them
773		// before any dispatch attempt. This is the synchronous-freshness
774		// contract from FEAT-004 §Snapshot Freshness — autorouting reads the
775		// snapshot, the snapshot owns reachability evidence, and stale-but-
776		// failed providers don't get re-dialed until the cooldown TTL expires.
777		healthCooldownTTL := s.routeAttemptTTL()
778		providerUnreachable := providerCooldownsFromSnapshotErrors(snapshot, s.opts.ServiceConfig, now, healthCooldownTTL)
779	
780		return routing.Inputs{
781			Harnesses:                    entries,
782			ProviderSuccessRate:          successRate,
783			ObservedLatencyMS:            latencyMS,
784			ProviderQuotaExhaustedUntil:  s.providerQuotaExhaustedUntil(now),
785			ProviderUnreachable:          providerUnreachable,
786			CooldownDuration:             healthCooldownTTL,
787			Now:                          now,
788			ModelEligibility:             serviceRoutingModelEligibility(entries, cat),
789			ReasoningResolver:            serviceRoutingReasoningResolver(cat),
790			EndpointLoadResolver:         s.routeEndpointLoadsResolver(now),
791			StickyServerInstanceResolver: s.routeStickyServerInstanceResolver(now),
792		}, snapshot
793	}
794	
795	// dispatchabilityFailureSubstrings matches errors that indicate the upstream
796	// host is unreachable or the provider is currently unusable: TCP-level dial
797	// failures, unrouted DNS, and HTTP 5xx gateway statuses (502/503/504/Bad
798	// Gateway). Treated as dispatchability failures per FEAT-004 AC-28. Both
799	// snapshot discovery errors and route-attempt record errors are classified
800	// through this same predicate.
801	//
802	// Excluded on purpose:
803	//   - 429 / rate-limit (different state machine, ProviderQuotaExhaustedUntil)
804	//   - "context canceled" (operator interrupt; not a provider signal)
805	//   - "provider request timeout: wall-clock" (could mean slow but live host)
806	//   - generic 4xx (auth, validation — surfaces via FilterReasonAuth elsewhere)
807	var dispatchabilityFailureSubstrings = []string{
808		"dial tcp",
809		"connection refused",
810		"no route to host",
811		"network is unreachable",
812		"i/o timeout",
813		"no such host",
814		"502 bad gateway",
815		"503 service unavailable",
816		"504 gateway timeout",
817		" 502 ", // bare status code form (e.g. `: 502 Bad Gateway`)
818		" 503 ",
819		" 504 ",
820	}
