826	func isDispatchabilityFailure(errMsg string) bool {
827		if errMsg == "" {
828			return false
829		}
830		lower := strings.ToLower(errMsg)
831		for _, pat := range dispatchabilityFailureSubstrings {
832			if strings.Contains(lower, pat) {
