839	// providerCooldownsFromSnapshotErrors walks snapshot.Sources and returns a map
840	// of providerName → failure-time for any provider whose most recent discovery
841	// attempt failed with a dial-class error within the cooldown window. The map
842	// feeds routing.Inputs.ProviderCooldowns so engine.go can hard-gate the
843	// candidate before any dispatch attempt.
844	//
845	// Source names are produced by endpointSourceName: they start with the
846	// provider name (optionally followed by "-<endpoint>-<hash>" or "-props").
847	// We match by prefix against the configured provider name set so a source
848	// name like "rg-bragi-club-3090-props" correctly maps to provider
849	// "rg-bragi-club-3090".
850	func providerCooldownsFromSnapshotErrors(snapshot modelsnapshot.ModelSnapshot, cfg ServiceConfigSource, now time.Time, ttl time.Duration) map[string]time.Time {
851		if len(snapshot.Sources) == 0 {
852			return nil
853		}
854		providerNames := []string{}
855		if cfg != nil {
856			providerNames = cfg.ProviderNames()
857		}
858		if len(providerNames) == 0 {
859			return nil
860		}
861		// Sort longest first so "rg-bragi-club-3090" wins over a hypothetical
862		// "rg-bragi" prefix when both are configured.
863		sort.SliceStable(providerNames, func(i, j int) bool {
864			return len(providerNames[i]) > len(providerNames[j])
865		})
866	
867		cooldowns := make(map[string]time.Time)
868		for srcName, meta := range snapshot.Sources {
869			if !isSnapshotDialFailure(meta.Error) {
870				continue
871			}
872			// Use LastRefreshedAt when present (when the cache holds the failure
873			// record itself); otherwise treat as "fresh enough" — the discovery
874			// only emits an error when it tried recently.
875			failedAt := meta.LastRefreshedAt
876			if failedAt.IsZero() {
877				failedAt = now
878			}
879			if ttl > 0 && now.Sub(failedAt) >= ttl {
880				continue
881			}
882			for _, name := range providerNames {
883				if name == srcName || strings.HasPrefix(srcName, name+"-") {
884					if existing, ok := cooldowns[name]; !ok || failedAt.After(existing) {
885						cooldowns[name] = failedAt
886					}
887					break
888				}
889			}
890		}
891		if len(cooldowns) == 0 {
892			return nil
893		}
894		return cooldowns
895	}
