904	func (s *service) snapshotProviderEntries(ctx context.Context, cat *modelcatalog.Catalog, snapshot modelsnapshot.ModelSnapshot) []routing.ProviderEntry {
905		if s == nil || s.opts.ServiceConfig == nil {
906			return nil
907		}
908		providerNames := s.opts.ServiceConfig.ProviderNames()
909		if len(providerNames) == 0 || len(snapshot.Models) == 0 {
910			return nil
911		}
912		grouped := make(map[snapshotProviderGroupKey][]modelsnapshot.KnownModel)
913		for _, row := range snapshot.Models {
914			harness := strings.TrimSpace(row.Harness)
915			if harness != "" && harness != "fiz" {
916				continue
917			}
918			providerName := strings.TrimSpace(row.Provider)
919			if providerName == "" {
920				continue
921			}
922			if _, ok := s.opts.ServiceConfig.Provider(providerName); !ok {
923				continue
924			}
925			key := snapshotProviderGroupKey{
926				Provider:        providerName,
927				EndpointName:    strings.TrimSpace(row.EndpointName),
928				EndpointBaseURL: strings.TrimSpace(row.EndpointBaseURL),
929				ServerInstance:  strings.TrimSpace(row.ServerInstance),
930			}
931			grouped[key] = append(grouped[key], row)
932		}
933		if len(grouped) == 0 {
934			return nil
935		}
936	
937		groupCountByProvider := make(map[string]int)
938		for key := range grouped {
939			groupCountByProvider[key.Provider]++
940		}
941	
942		keys := make([]snapshotProviderGroupKey, 0, len(grouped))
943		for key := range grouped {
944			keys = append(keys, key)
945		}
946		sort.Slice(keys, func(i, j int) bool {
947			if keys[i].Provider != keys[j].Provider {
948				return keys[i].Provider < keys[j].Provider
949			}
950			if keys[i].EndpointName != keys[j].EndpointName {
951				return keys[i].EndpointName < keys[j].EndpointName
952			}
953			if keys[i].EndpointBaseURL != keys[j].EndpointBaseURL {
954				return keys[i].EndpointBaseURL < keys[j].EndpointBaseURL
955			}
956			return keys[i].ServerInstance < keys[j].ServerInstance
957		})
958	
959		var entries []routing.ProviderEntry
960		for _, key := range keys {
961			pcfg, ok := s.opts.ServiceConfig.Provider(key.Provider)
962			if !ok || pcfg.ConfigError != "" {
963				continue
964			}
965			rows := append([]modelsnapshot.KnownModel(nil), grouped[key]...)
966			sort.Slice(rows, func(i, j int) bool {
967				if rows[i].EndpointName != rows[j].EndpointName {
968					return rows[i].EndpointName < rows[j].EndpointName
969				}
970				if rows[i].EndpointBaseURL != rows[j].EndpointBaseURL {
971					return rows[i].EndpointBaseURL < rows[j].EndpointBaseURL
972				}
973				if rows[i].ServerInstance != rows[j].ServerInstance {
974					return rows[i].ServerInstance < rows[j].ServerInstance
975				}
976				return rows[i].ID < rows[j].ID
977			})
978			discoveredIDs := snapshotModelIDs(rows)
979			if defaultModel := strings.TrimSpace(pcfg.Model); defaultModel != "" {
980				discoveredIDs = appendUniqueModelIDs(discoveredIDs, defaultModel)
981			}
982			ctxWindows, ctxSources := snapshotProviderContextWindows(ctx, pcfg, cat, rows, discoveredIDs)
983			endpointName := snapshotEndpointName(pcfg, key)
984			routeName := key.Provider
985			if groupCountByProvider[key.Provider] > 1 {
986				switch {
987				case endpointName != "":
988					routeName = endpointProviderRef(key.Provider, endpointName)
989				case key.ServerInstance != "":
990					routeName = endpointProviderRef(key.Provider, key.ServerInstance)
991				case key.EndpointBaseURL != "":
992					routeName = endpointProviderRef(key.Provider, key.EndpointBaseURL)
993				}
994			}
995			baseURL := key.EndpointBaseURL
996			if baseURL == "" {
997				baseURL = pcfg.BaseURL
998			}
999			serverInstance := key.ServerInstance
1000			if serverInstance == "" {
1001				serverInstance = pcfg.ServerInstance
1002			}
1003			serverInstance = serverinstance.Normalize(baseURL, serverInstance)
1004			entry := routing.ProviderEntry{
1005				Name:                      routeName,
1006				BaseURL:                   baseURL,
1007				ServerInstance:            serverInstance,
1008				EndpointName:              endpointName,
1009				EndpointBaseURL:           baseURL,
1010				DefaultModel:              pcfg.Model,
1011				Billing:                   pcfg.Billing,
1012				CostClass:                 providerRoutingCostClass(pcfg.Type),
1013				DiscoveredIDs:             discoveredIDs,
1014				DiscoveryAttempted:        true,
1015				ContextWindows:            ctxWindows,
1016				ContextWindowSources:      ctxSources,
1017				ContextWindow:             pcfg.ContextWindow,
1018				ContextWindowSource:       contextWindowSourceForProviderConfig(pcfg),
1019				SupportsTools:             providerSupportsTools(cat, pcfg.Model, discoveredIDs),
1020				ExcludeFromDefaultRouting: pcfg.IncludeByDefaultSet && !pcfg.IncludeByDefault,
1021			}
1022			s.applyEndpointRoutingCost(&entry, pcfg, cat)
1023			entries = append(entries, entry)
1024		}
1025		return entries
1026	}
