1035	func snapshotEndpointName(pcfg ServiceProviderEntry, key snapshotProviderGroupKey) string {
1036		endpoints := modelDiscoveryEndpoints(pcfg)
1037		trimmedEndpointName := strings.TrimSpace(key.EndpointName)
1038		trimmedBaseURL := strings.TrimSpace(key.EndpointBaseURL)
1039		trimmedServerInstance := strings.TrimSpace(key.ServerInstance)
1040		if len(endpoints) == 0 {
1041			if trimmedEndpointName != "" {
1042				if strings.EqualFold(trimmedEndpointName, strings.TrimSpace(key.Provider)) {
1043					return "default"
1044				}
1045				return trimmedEndpointName
1046			}
1047			if trimmedServerInstance != "" {
1048				return trimmedServerInstance
1049			}
1050			if trimmedBaseURL != "" {
1051				return trimmedBaseURL
1052			}
1053			return ""
1054		}
1055		for _, endpoint := range endpoints {
1056			if trimmedEndpointName != "" && strings.EqualFold(endpoint.Name, trimmedEndpointName) {
1057				return endpoint.Name
1058			}
1059			if trimmedBaseURL != "" && strings.TrimSpace(endpoint.BaseURL) == trimmedBaseURL {
1060				return endpoint.Name
1061			}
1062			if trimmedServerInstance != "" && strings.TrimSpace(endpoint.ServerInstance) == trimmedServerInstance {
1063				return endpoint.Name
1064			}
1065		}
1066		if len(endpoints) == 1 {
1067			return endpoints[0].Name
1068		}
1069		if trimmedEndpointName != "" {
1070			return trimmedEndpointName
1071		}
1072		if trimmedServerInstance != "" {
1073			return trimmedServerInstance
1074		}
1075		if trimmedBaseURL != "" {
1076			return trimmedBaseURL
1077		}
1078		return ""
1079	}
