1102	func snapshotProviderContextWindows(ctx context.Context, pcfg ServiceProviderEntry, cat *modelcatalog.Catalog, rows []modelsnapshot.KnownModel, discoveredIDs []string) (map[string]int, map[string]string) {
1103		_ = ctx
1104		out := make(map[string]int)
1105		sources := make(map[string]string)
1106		rowByID := make(map[string]modelsnapshot.KnownModel, len(rows))
1107		for _, row := range rows {
1108			id := strings.TrimSpace(row.ID)
1109			if id == "" {
1110				continue
1111			}
1112			if _, exists := rowByID[id]; !exists {
1113				rowByID[id] = row
1114			}
1115		}
1116		add := func(modelID string, snapshotWindow int) {
1117			modelID = strings.TrimSpace(modelID)
1118			if modelID == "" {
1119				return
1120			}
1121			window, source := snapshotContextWindow(pcfg, cat, modelID, snapshotWindow)
1122			if window <= 0 {
1123				return
1124			}
1125			out[modelID] = window
1126			sources[modelID] = source
1127		}
1128		if defaultModel := strings.TrimSpace(pcfg.Model); defaultModel != "" {
1129			row, ok := rowByID[defaultModel]
1130			if ok {
1131				add(defaultModel, row.ContextWindow)
1132			} else {
1133				add(defaultModel, 0)
1134			}
1135		}
1136		for _, id := range discoveredIDs {
1137			row, ok := rowByID[id]
1138			if ok {
1139				add(id, row.ContextWindow)
1140				continue
1141			}
1142			add(id, 0)
1143		}
1144		if len(out) == 0 {
1145			return nil, nil
1146		}
1147		return out, sources
1148	}
