1176	// startQuotaRecoveryProbeLoop spawns the goroutine that periodically probes
1177	// quota_exhausted providers and either restores them to available or extends
1178	// their retry_after with bounded backoff. The goroutine is tied to
1179	// QuotaRefreshContext (or context.Background()) so server callers can cancel
1180	// it on shutdown.
1181	func (s *service) startQuotaRecoveryProbeLoop() {
1182		if s == nil || s.providerQuota == nil {
1183			return
1184		}
1185		ctx := s.opts.QuotaRefreshContext
1186		if ctx == nil {
1187			ctx = context.Background()
1188		}
1189		probe := s.quotaRecoveryProber()
1190		if probe == nil {
1191			return
1192		}
1193		go runQuotaRecoveryProbeLoop(ctx, s.providerQuota, probe, defaultQuotaRecoveryFallbackInterval, nil, nil)
1194	}
