1196	// quotaRecoveryProber returns the QuotaRecoveryProber used by the recovery
1197	// loop. It looks up the provider entry in ServiceConfig and reuses the same
1198	// probeProviderStatus the HealthCheck endpoint uses; a "connected" status
1199	// counts as recovery, anything else is reported as a probe failure so the
1200	// retry_after gets extended with backoff.
1201	func (s *service) quotaRecoveryProber() QuotaRecoveryProber {
1202		sc := s.opts.ServiceConfig
1203		if sc == nil {
1204			return nil
1205		}
1206		return func(ctx context.Context, name string) error {
1207			entry, ok := sc.Provider(name)
1208			if !ok {
1209				return fmt.Errorf("provider %q not found", name)
1210			}
1211			probeCtx, cancel := context.WithTimeout(ctx, 5*time.Second)
1212			defer cancel()
1213			probe := probeProviderStatus(probeCtx, entry, time.Now().UTC())
1214			if probe.status == "connected" {
1215				return nil
1216			}
1217			if probe.detail != "" {
1218				return fmt.Errorf("%s", probe.detail)
1219			}
1220			return fmt.Errorf("%s", probe.status)
1221		}
1222	}
