1316	func serviceRoutingModelEligibility(entries []routing.HarnessEntry, cat *modelcatalog.Catalog) func(model string) (routing.ModelEligibility, bool) {
1317		if cat == nil {
1318			return nil
1319		}
1320		eligibility := make(map[string]routing.ModelEligibility)
1321		add := func(modelID string, includeByDefault bool, status string) {
1322			modelID = strings.TrimSpace(modelID)
1323			if modelID == "" {
1324				return
1325			}
1326			view := modeleligibility.Resolve(modelID, includeByDefault, status, cat)
1327			known := routing.ModelEligibility{
1328				Power:        view.Power,
1329				ExactPinOnly: view.ExactPinOnly,
1330				AutoRoutable: view.AutoRoutable,
1331			}
1332			if existing, ok := eligibility[modelID]; ok {
1333				if known.Power > existing.Power {
1334					existing.Power = known.Power
1335				}
1336				existing.ExactPinOnly = existing.ExactPinOnly || known.ExactPinOnly
1337				existing.AutoRoutable = existing.AutoRoutable || known.AutoRoutable
1338				eligibility[modelID] = existing
1339				return
1340			}
1341			eligibility[modelID] = known
1342		}
1343		for _, h := range entries {
1344			status := "available"
1345			if !h.Available {
1346				status = "unreachable"
1347			}
1348			if h.DefaultModel != "" {
1349				add(h.DefaultModel, true, status)
1350			}
1351			for _, modelID := range h.SupportedModels {
1352				add(modelID, true, status)
1353			}
1354			for _, p := range h.Providers {
1355				includeByDefault := !p.ExcludeFromDefaultRouting
1356				add(p.DefaultModel, includeByDefault, status)
1357				for _, modelID := range p.DiscoveredIDs {
1358					add(modelID, includeByDefault, status)
1359				}
1360			}
1361		}
1362		if len(eligibility) == 0 {
1363			return nil
1364		}
1365		return func(model string) (routing.ModelEligibility, bool) {
1366			known, ok := eligibility[strings.TrimSpace(model)]
1367			return known, ok
1368		}
1369	}
