1567	func catalogCostUSDPer1kTokens(cat *modelcatalog.Catalog, modelID string) (float64, bool) {
1568		if cat == nil || strings.TrimSpace(modelID) == "" {
1569			return 0, false
1570		}
1571		entry, ok := cat.LookupModel(modelID)
1572		if !ok {
1573			resolved := resolveCatalogCostModel(cat, modelID)
1574			if resolved == "" {
1575				return 0, false
1576			}
1577			entry, ok = cat.LookupModel(resolved)
1578			if !ok {
1579				return 0, false
1580			}
1581		}
1582		input := entry.CostInputPerM
1583		if input == 0 {
1584			input = entry.CostInputPerMTok
1585		}
1586		output := entry.CostOutputPerM
1587		if output == 0 {
1588			output = entry.CostOutputPerMTok
1589		}
1590		switch {
1591		case input > 0 && output > 0:
1592			return ((input + output) / 2) / 1000, true
1593		case input > 0:
1594			return input / 1000, true
1595		case output > 0:
1596			return output / 1000, true
1597		default:
1598			return 0, false
1599		}
1600	}
