1625		curve := *s.opts.SubscriptionCostCurve
1626		def := defaultSubscriptionCostCurve()
1627		if curve.FreeUntilPercent == 0 {
1628			curve.FreeUntilPercent = def.FreeUntilPercent
1629		}
1630		if curve.LowUntilPercent == 0 {
1631			curve.LowUntilPercent = def.LowUntilPercent
1632		}
1633		if curve.MediumUntilPercent == 0 {
1634			curve.MediumUntilPercent = def.MediumUntilPercent
1635		}
1636		if curve.LowMultiplier == 0 {
1637			curve.LowMultiplier = def.LowMultiplier
1638		}
1639		if curve.MediumMultiplier == 0 {
1640			curve.MediumMultiplier = def.MediumMultiplier
1641		}
1642		if curve.HighMultiplier == 0 {
1643			curve.HighMultiplier = def.HighMultiplier
