1659	func subscriptionEffectiveCostUSDPer1kTokens(baseCost float64, quotaPercentUsed int, curve SubscriptionCostCurve) float64 {
1660		switch {
1661		case quotaPercentUsed <= curve.FreeUntilPercent:
1662			return 0
1663		case quotaPercentUsed <= curve.LowUntilPercent:
1664			return baseCost * curve.LowMultiplier
1665		case quotaPercentUsed <= curve.MediumUntilPercent:
1666			return baseCost * curve.MediumMultiplier
1667		default:
1668			return baseCost * curve.HighMultiplier
1669		}
1670	}
