1700	func providerPreferenceForPolicy(cat *modelcatalog.Catalog, policy string) (string, error) {
1701		if policy == "" {
1702			return routing.ProviderPreferenceLocalFirst, nil
1703		}
1704		switch policy {
1705		case "code-medium":
1706			return "", fmt.Errorf("policy %q is deprecated; use --policy default or --min-power/--max-power", policy)
1707		case "code-high":
1708			return "", fmt.Errorf("policy %q is deprecated; use --policy smart or --min-power/--max-power", policy)
1709		}
1710		if cat == nil {
1711			return "", &ErrUnknownPolicy{Policy: policy}
1712		}
1713		if _, _, ok := policyForName(cat, policy); !ok {
1714			return "", &ErrUnknownPolicy{Policy: policy}
1715		}
1716		preference := providerPreferenceForPolicyName(policy)
1717		switch preference {
1718		case routing.ProviderPreferenceLocalOnly, routing.ProviderPreferenceSubscriptionOnly,
1719			routing.ProviderPreferenceLocalFirst, routing.ProviderPreferenceSubscriptionFirst:
1720			return preference, nil
1721		default:
1722			return "", fmt.Errorf("policy %q has unsupported provider preference %q", policy, preference)
1723		}
1724	}
