1726	func routePowerPolicyForRequest(cat *modelcatalog.Catalog, req RouteRequest) RoutePowerPolicy {
1727		policy := RoutePowerPolicy{
1728			PolicyName: req.Policy,
1729			MinPower:   req.MinPower,
1730			MaxPower:   req.MaxPower,
1731		}
1732		if req.Policy == "" || cat == nil {
1733			return policy
1734		}
1735		policyEntry, policyName, ok := policyForName(cat, req.Policy)
1736		if !ok {
1737			return policy
1738		}
1739		policy.PolicyName = policyName
1740		if policyEntry.MinPower > 0 {
1741			if policy.MinPower == 0 || policyEntry.MinPower > policy.MinPower {
1742				policy.MinPower = policyEntry.MinPower
1743			}
1744		}
1745		if policyEntry.MaxPower > 0 {
1746			if policy.MaxPower == 0 || policyEntry.MaxPower < policy.MaxPower {
1747				policy.MaxPower = policyEntry.MaxPower
1748			}
1749		}
1750		return policy
1751	}
